while (reader.readNextPacket(raw)) {
    Packet pkt = createPacket(raw);

    // Hash to select Load Balancer
    size_t lb_idx = hash(pkt.tuple) % num_lbs;

    // Push to LB's queue
    lbs_[lb_idx]->queue().push(pkt);
} Step 2: Load Balancer Thread void LoadBalancer::run() {
    while (running_) {
        // Pop from my input queue
        auto pkt = input_queue_.pop();

        // Hash to select Fast Path
        size_t fp_idx = hash(pkt.tuple) % num_fps_;

        // Push to FP's queue
        fps_[fp_idx]->queue().push(pkt);
    }
} Step 3: Fast Path Thread void FastPath::run() {
    while (running_) {
        // Pop from my input queue
        auto pkt = input_queue_.pop();

        // Look up flow (each FP has its own flow table)
        Flow& flow = flows_[pkt.tuple];

        // Classify (SNI extraction)
        classifyFlow(pkt, flow);

        // Check rules
        if (rules_->isBlocked(pkt.tuple.src_ip, flow.app_type, flow.sni)) {
            stats_->dropped++;
        } else {
            // Forward: push to output queue
            output_queue_->push(pkt);
        }
    }
} Step 4: Output Writer Thread void outputThread() {
    while (running_ || output_queue_.size() > 0) {
        auto pkt = output_queue_.pop();

        // Write to output file
        output_file.write(packet_header);
        output_file.write(pkt.data);
    }
} Thread-Safe Queue The magic that makes multi-threading work: template<typename T>
class TSQueue {
    std::queue<T> queue_;
    std::mutex mutex_;
    std::condition_variable not_empty_;
    std::condition_variable not_full_;

    void push(T item) {
        std::lock_guard<std::mutex> lock(mutex_);
        queue_.push(item);
        not_empty_.notify_one();  // Wake up waiting consumer
    }

    T pop() {
        std::unique_lock<std::mutex> lock(mutex_);
        not_empty_.wait(lock, [&]{ return !queue_.empty(); });
        T item = queue_.front();
        queue_.pop();
        return item;
    }
}; How it works: push(): Producer adds item, signals waiting consumers pop(): Consumer waits until item available, then takes it mutex: Only one thread can access at a time condition_variable: Efficient waiting (no busy-loop) 7. Deep Dive: Each Component pcap_reader.h / pcap_reader.cpp Purpose: Read network captures saved by Wireshark Key structures: struct PcapGlobalHeader {
